SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT mt.TEST_SNO, mt.ORG_ID, o.ORG_NAME, mt.TRX_ID, mt.TEST_NAME, mt.TEST_DESC, mt.USER_ID, mt.TEST_DATA
ORDER BY
mt.TEST_SNO o.ORG_NAME mt.TRX_ID mt.TEST_NAME mt.TEST_DESC mt.USER_ID mt.LAST_UPDATE_DTIME
ASC DESC
ORDER BY mt.LAST_UPDATE_DTIME DESC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}

WITH message_chain (MESSAGE_ID, PARENT_MESSAGE_ID, depth) AS ( -- Anchor: 시작 메시지 (자식) SELECT MESSAGE_ID, PARENT_MESSAGE_ID, 1 AS depth FROM FWK_MESSAGE WHERE ORG_ID = #{orgId} AND MESSAGE_ID = #{messageId}
UNION ALL
-- Recursive: 부모 메시지 탐색 SELECT m.MESSAGE_ID, m.PARENT_MESSAGE_ID, mc.depth + 1 AS depth FROM FWK_MESSAGE m INNER JOIN message_chain mc ON m.MESSAGE_ID = mc.PARENT_MESSAGE_ID AND m.ORG_ID = #{orgId} WHERE mc.depth < 10 -- 최대 10단계까지만 탐색 ) SELECT MESSAGE_ID FROM message_chain ORDER BY depth DESC -- 부모 → 자식 순서 (depth 역순: 큰 depth부터)

SELECT tm.ORG_ID, o.ORG_NAME, tm.TRX_ID, t.TRX_NAME, tm.IO_TYPE, CASE WHEN tm.IO_TYPE = 'I' THEN NVL(tm.RES_MESSAGE_ID, tm.MESSAGE_ID) WHEN tm.IO_TYPE = 'O' THEN tm.MESSAGE_ID ELSE tm.MESSAGE_ID END AS MESSAGE_ID FROM FWK_TRX_MESSAGE tm JOIN FWK_ORG o ON tm.ORG_ID = o.ORG_ID JOIN FWK_TRX t ON tm.TRX_ID = t.TRX_ID
WHERE tm.IO_TYPE = #{ioType}
AND tm.ORG_ID = #{orgId}
AND tm.TRX_ID LIKE '%' || #{trxId} || '%'
AND t.TRX_NAME LIKE '%' || #{trxName} || '%'
ORDER BY tm.TRX_ID, tm.IO_TYPE

SELECT TEST_SNO, TEST_NAME, PROXY_VALUE, DEFAULT_PROXY_YN, USER_ID, PROXY_FIELD FROM FWK_MESSAGE_TEST WHERE ORG_ID = #{orgId} AND TRX_ID = #{trxId}
AND TEST_GROUP_ID = #{testGroupId}
AND TEST_NAME LIKE '%' || #{testName} || '%'
AND USER_ID LIKE '%' || #{userId} || '%'
ORDER BY TEST_SNO

SELECT DISTINCT TEST_GROUP_ID
FROM FWK_MESSAGE_TEST
WHERE ORG_ID = #{orgId}
  AND TRX_ID = #{trxId}
ORDER BY TEST_GROUP_ID
